CREATE PROC [dbo].[CREATE_AT] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('AT','U') IS NOT NULL    DROP TABLE AT IF OBJECT_ID('AT_Info','U') IS NOT NULL DROP TABLE AT_Info  CREATE TABLE AT ([Place Of Supply] varchar(32) ,[Rate] decimal ,[Gross Advance Received] decimal ,[CESS Amount] decimal ) CREATE TABLE AT_Info ( [Total Advance Recieved] decimal, [Total Cess] decimal ) INSERT INTO AT_Info VALUES(0,0) IF OBJECT_ID('AT_Header','U') IS NULL CREATE TABLE AT_Header ([Summary For Advance Received (11B) ] Char(1) ) INSERT INTO InfoTable Values('AT',2,'<<Default>>','AT',7) 